CREATE TRIGGER "rtree_Added geometry info_geom_update5" AFTER UPDATE ON "Added geometry info" WHEN OLD."fid" != NEW."fid" AND (NEW."geom" NOTNULL AND NOT ST_IsEmpty(NEW."geom")) BEGIN DELETE FROM "rtree_Added geometry info_geom" WHERE id = OLD."fid"; INSERT OR REPLACE INTO "rtree_Added geometry info_geom" VALUES (NEW."fid",ST_MinX(NEW."geom"), ST_MaxX(NEW."geom"),ST_MinY(NEW."geom"), ST_MaxY(NEW."geom")); END;
CREATE TRIGGER "rtree_Added geometry info_geom_update4" AFTER UPDATE ON "Added geometry info" WHEN OLD."fid" != NEW."fid" AND (NEW."geom" ISNULL OR ST_IsEmpty(NEW."geom")) BEGIN DELETE FROM "rtree_Added geometry info_geom" WHERE id IN (OLD."fid", NEW."fid"); END;
CREATE TRIGGER "rtree_Added geometry info_geom_delete" AFTER DELETE ON "Added geometry info" WHEN old."geom" NOT NULL BEGIN DELETE FROM "rtree_Added geometry info_geom" WHERE id = OLD."fid"; END;
