CREATE VIRTUAL TABLE "rtree_unibfix_geom" USING rtree(id, minx, maxx, miny, maxy);
CREATE TABLE IF NOT EXISTS "rtree_unibfix_geom_rowid"(rowid INTEGER PRIMARY KEY,nodeno);
CREATE TABLE IF NOT EXISTS "rtree_unibfix_geom_node"(nodeno INTEGER PRIMARY KEY,data);
CREATE TABLE IF NOT EXISTS "rtree_unibfix_geom_parent"(nodeno INTEGER PRIMARY KEY,parentnode);
CREATE TRIGGER "rtree_unibfix_geom_insert" AFTER INSERT ON "unibfix" WHEN (new."geom" NOT NULL AND NOT ST_IsEmpty(NEW."geom")) BEGIN INSERT OR REPLACE INTO "rtree_unibfix_geom" VALUES (NEW."fid",ST_MinX(NEW."geom"), ST_MaxX(NEW."geom"),ST_MinY(NEW."geom"), ST_MaxY(NEW."geom")); END;
CREATE TRIGGER "rtree_unibfix_geom_update6" AFTER UPDATE OF "geom" ON "unibfix" WHEN OLD."fid" = NEW."fid" AND (NEW."geom" NOTNULL AND NOT ST_IsEmpty(NEW."geom")) AND (OLD."geom" NOTNULL AND NOT ST_IsEmpty(OLD."geom")) BEGIN UPDATE "rtree_unibfix_geom" SET minx = ST_MinX(NEW."geom"), maxx = ST_MaxX(NEW."geom"),miny = ST_MinY(NEW."geom"), maxy = ST_MaxY(NEW."geom") WHERE id = NEW."fid";END;
CREATE TRIGGER "rtree_unibfix_geom_update7" AFTER UPDATE OF "geom" ON "unibfix" WHEN OLD."fid" = NEW."fid" AND (NEW."geom" NOTNULL AND NOT ST_IsEmpty(NEW."geom")) AND (OLD."geom" ISNULL OR ST_IsEmpty(OLD."geom")) BEGIN INSERT INTO "rtree_unibfix_geom" VALUES (NEW."fid",ST_MinX(NEW."geom"), ST_MaxX(NEW."geom"),ST_MinY(NEW."geom"), ST_MaxY(NEW."geom")); END;
CREATE TRIGGER "rtree_unibfix_geom_update2" AFTER UPDATE OF "geom" ON "unibfix" WHEN OLD."fid" = NEW."fid" AND (NEW."geom" ISNULL OR ST_IsEmpty(NEW."geom")) BEGIN DELETE FROM "rtree_unibfix_geom" WHERE id = OLD."fid"; END;
CREATE TRIGGER "rtree_unibfix_geom_update5" AFTER UPDATE ON "unibfix" WHEN OLD."fid" != NEW."fid" AND (NEW."geom" NOTNULL AND NOT ST_IsEmpty(NEW."geom")) BEGIN DELETE FROM "rtree_unibfix_geom" WHERE id = OLD."fid"; INSERT OR REPLACE INTO "rtree_unibfix_geom" VALUES (NEW."fid",ST_MinX(NEW."geom"), ST_MaxX(NEW."geom"),ST_MinY(NEW."geom"), ST_MaxY(NEW."geom")); END;
CREATE TRIGGER "rtree_unibfix_geom_update4" AFTER UPDATE ON "unibfix" WHEN OLD."fid" != NEW."fid" AND (NEW."geom" ISNULL OR ST_IsEmpty(NEW."geom")) BEGIN DELETE FROM "rtree_unibfix_geom" WHERE id IN (OLD."fid", NEW."fid"); END;
CREATE TRIGGER "rtree_unibfix_geom_delete" AFTER DELETE ON "unibfix" WHEN old."geom" NOT NULL BEGIN DELETE FROM "rtree_unibfix_geom" WHERE id = OLD."fid"; END;
CREATE TRIGGER "trigger_insert_feature_count_unibfix" AFTER INSERT ON "unibfix" BEGIN UPDATE gpkg_ogr_contents SET feature_count = feature_count + 1 WHERE lower(table_name) = lower('unibfix'); END;
CREATE TRIGGER "trigger_delete_feature_count_unibfix" AFTER DELETE ON "unibfix" BEGIN UPDATE gpkg_ogr_contents SET feature_count = feature_count - 1 WHERE lower(table_name) = lower('unibfix'); END;
CREATE TRIGGER "trigger_insert_feature_count_layer_styles" AFTER INSERT ON "layer_styles" BEGIN UPDATE gpkg_ogr_contents SET feature_count = feature_count + 1 WHERE lower(table_name) = lower('layer_styles'); END;
CREATE TRIGGER "trigger_delete_feature_count_layer_styles" AFTER DELETE ON "layer_styles" BEGIN UPDATE gpkg_ogr_contents SET feature_count = feature_count - 1 WHERE lower(table_name) = lower('layer_styles'); END;
